    "/api/actions/lifecycle",
    "/api/trpc/lifecycle.run",
    "/api/customer-lifecycle",
])

tested = 0
for path in paths_to_try:
    url = f"{base}{path}"
    try:
        req = urllib.request.Request(url)
        with urllib.request.urlopen(req, timeout=8) as resp:
            body = resp.read().decode()[:500]
            print(f"FOUND: {path} -> {resp.status}")
            print(f"  {body[:200]}")
            break
    except urllib.error.HTTPError as e:
        if e.code != 404:
            print(f"NON-404: {path} -> {e.code}")
        tested += 1
    except Exception as e:
        print(f"ERROR: {path} -> {e}")
else:
    print(f"Tested {tested} paths, all 404.")
